INSERT INTO posts (title, slug, category, description, content, tags, status) VALUES 
('경찰에게 잡혀가는 꿈 해몽, 수갑 차고 끌려가는 꿈의 의미', 'dream-police-arrest-1', '꿈해몽', '경찰에게 잡혀가는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n경찰에게 잡혀가는 꿈은 매우 당혹스럽고 무서운 경험일 수 있습니다.\n\n## 이 꿈의 일반적인 의미\n보통 사회적 규칙이나 도덕적 양심과 관련된 압박감을 상징합니다.\n\n## 심리적으로 볼 때의 의미\n현재 일상에서 무언가 잘못했다는 죄책감이나, 타인의 시선을 과도하게 의식하고 있을 가능성이 있습니다.\n\n## 상황별 해석\n- 수갑을 차는 경우: 행동의 제약이나 자유의 억압을 느낄 때\n- 억울하게 잡혀가는 경우: 주변의 오해나 부당한 대우에 대한 불안\n\n## 좋은 의미로 볼 수 있는 경우\n자신의 행동을 되돌아보고 바른 길로 나아가는 계기가 될 수 있습니다.\n\n## 주의가 필요한 경우\n과도한 스트레스로 인해 심신이 지쳐있을 수 있습니다.\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "불안"]', 'draft'),

('경찰 조사를 받는 꿈 해몽, 집에서 조사받는 꿈 풀이', 'dream-police-investigation-1', '꿈해몽', '경찰 조사를 받는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n누군가에게 심문을 받거나 조사를 받는 꿈은 압박감을 줍니다.\n\n## 이 꿈의 일반적인 의미\n자신의 비밀이 탄로날까 두려워하거나, 평가받는 상황에 대한 불안을 의미합니다.\n\n## 심리적으로 볼 때의 의미\n완벽주의적 성향이 강하거나, 최근 실수를 했을 때 자주 나타날 수 있습니다.\n\n## 상황별 해석\n- 집에서 조사받는 경우: 가장 편안해야 할 공간조차 침해받는 느낌\n- 당당하게 조사받는 경우: 당면한 문제를 해결하려는 의지\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "압박감"]', 'draft'),

('사채업자가 집에 찾아오는 꿈 해몽, 채권자에게 쫓기는 꿈', 'dream-debt-collector-1', '꿈해몽', '사채업자가 찾아오는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n금전적인 압박이나 해결되지 않은 부채와 관련된 꿈입니다.\n\n## 이 꿈의 일반적인 의미\n실제 금전 문제일 수도 있지만, 심리적인 "마음의 빚"을 상징하기도 합니다.\n\n## 심리적으로 볼 때의 의미\n약속을 지키지 못했거나, 누군가에게 미안한 마음이 있을 때 나타납니다.\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "스트레스"]', 'draft'),

('형사에게 쫓기는 꿈 해몽, 낭떠러지에서 뛰어내리는 꿈', 'dream-detective-chase-1', '꿈해몽', '형사에게 쫓기는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n쫓기는 꿈은 가장 흔한 악몽 중 하나입니다.\n\n## 이 꿈의 일반적인 의미\n현실에서 도망치고 싶은 상황이나 책임감을 상징합니다.\n\n## 상황별 해석\n- 낭떠러지에서 뛰어내리는 경우: 막다른 길에서 내리는 중대한 결단 혹은 극심한 공포\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "도망"]', 'draft'),

('살인사건을 목격하는 꿈 해몽, 피가 뿜어져 나오는 꿈', 'dream-murder-witness-1', '꿈해몽', '살인사건을 목격하는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n충격적인 광경을 목격하는 꿈은 강렬한 메시지를 담고 있습니다.\n\n## 이 꿈의 일반적인 의미\n과거의 일과의 단절, 혹은 새로운 변화를 의미하기도 합니다.\n\n## 상황별 해석\n- 피가 뿜어져 나오는 경우: 막혔던 일이 풀리거나 에너지가 분출되는 긍정적 의미도 있음\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "변화"]', 'draft'),

('스토킹당하는 꿈 해몽, 깨진 유리로 테러당하는 꿈', 'dream-stalking-1', '꿈해몽', '스토킹당하는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n누군가 나를 계속 지켜보는 듯한 공포스러운 꿈입니다.\n\n## 이 꿈의 일반적인 의미\n개인적인 공간의 침해, 사생활 노출에 대한 불안을 상징합니다.\n\n## 상황별 해석\n- 깨진 유리로 테러당하는 경우: 관계의 상처나 날카로운 비판에 대한 두려움\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "공포"]', 'draft'),

('쫓기는 꿈 해몽, 반복해서 꾸는 도망치는 꿈의 의미', 'dream-chase-repeat-1', '꿈해몽', '반복해서 쫓기는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n왜 같은 꿈을 계속 꾸는 걸까요?\n\n## 이 꿈의 일반적인 의미\n해결되지 않은 갈등이 무의식 속에 남아있음을 뜻합니다.\n\n## 심리적으로 볼 때의 의미\n직면해야 할 문제를 계속 외면하고 있을 때 무의식은 경고를 보냅니다.\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "무의식"]', 'draft'),

('윗니가 전부 빠지는 꿈 해몽', 'dream-teeth-falling-1', '꿈해몽', '윗니가 빠지는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n이 빠지는 꿈은 예로부터 불길한 징조로 여겨져 왔습니다.\n\n## 이 꿈의 일반적인 의미\n가족이나 주변 지인에게 생길 수 있는 우환을 걱정하는 마음의 투영입니다.\n\n## 심리적으로 볼 때의 의미\n자신의 능력이 상실되거나, 자신감이 떨어졌을 때 자주 나타납니다.\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "불안"]', 'draft'),

('빠진 이빨을 다시 끼우는 꿈 해몽', 'dream-teeth-fix-1', '꿈해몽', '빠진 이빨을 끼우는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n이미 벌어진 일을 되돌리고 싶은 마음이 반영된 꿈입니다.\n\n## 이 꿈의 일반적인 의미\n실수를 만회하고 싶거나, 관계를 회복하려는 노력을 상징합니다.\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "회복"]', 'draft'),

('화장실을 입주청소 수준으로 청소하는 꿈 해몽', 'dream-cleaning-toilet-1', '꿈해몽', '화장실을 청소하는 꿈에 대한 풀이와 심리적인 의미를 알아봅니다.', '## 들어가며\n더러운 것을 닦아내는 행위는 정화를 의미합니다.\n\n## 이 꿈의 일반적인 의미\n마음의 짐을 털어내고 새로운 기분으로 시작하려는 의지를 뜻합니다.\n\n## 심리적으로 볼 때의 의미\n복잡했던 생각들이 정리되고 평온을 되찾아가는 과정입니다.\n\n## SimSimPlay 활용 안내\n꿈은 현재 마음 상태를 비추는 하나의 단서가 될 수 있습니다. 비슷한 꿈을 반복해서 꾼다면 SimSimPlay에서 오늘의 감정을 기록하고, 나에게 맞는 힐링음악을 추천받아보세요.', '["꿈해몽", "심리", "정화"]', 'draft');
